script:
frappe.ui.form.on("Sales Order", {
	channel_store(frm) {
		if (!frm.doc.channel_store) {
			return;
		}

		frappe.db.get_value("Channel Store", frm.doc.channel_store, "channel").then((response) => {
			const row = response.message || {};
			if (row.channel) {
				frm.set_value("channel", row.channel);
			}
		});
	}
});

frappe.ui.form.on("Sales Order Item", {
	item_code(frm, cdt, cdn) {
		const row = locals[cdt][cdn];
		if (!row.item_code) {
			return;
		}

		frappe.db.get_value(
			"Item",
			row.item_code,
			["style", "color_code", "color_name", "size_code", "size_name"]
		).then((response) => {
			const item = response.message || {};
			frappe.model.set_value(cdt, cdn, "style", item.style || "");
			frappe.model.set_value(cdt, cdn, "color_code", item.color_code || "");
			frappe.model.set_value(cdt, cdn, "color_name", item.color_name || "");
			frappe.model.set_value(cdt, cdn, "size_code", item.size_code || "");
			frappe.model.set_value(cdt, cdn, "size_name", item.size_name || "");
		});
	}
});

frappe.ui.form.on("Stock Entry Detail", {
	item_code(frm, cdt, cdn) {
		const row = locals[cdt][cdn];
		if (!row.item_code) {
			return;
		}

		frappe.db.get_value(
			"Item",
			row.item_code,
			["style", "color_code", "size_code"]
		).then((response) => {
			const item = response.message || {};
			frappe.model.set_value(cdt, cdn, "style", item.style || "");
			frappe.model.set_value(cdt, cdn, "color_code", item.color_code || "");
			frappe.model.set_value(cdt, cdn, "size_code", item.size_code || "");
		});
	},

	production_ticket(frm, cdt, cdn) {
		const row = locals[cdt][cdn];
		if (!row.production_ticket) {
			return;
		}

		frappe.db.get_value(
			"Production Ticket",
			row.production_ticket,
			["style", "color_code"]
		).then((response) => {
			const ticket = response.message || {};
			frappe.model.set_value(cdt, cdn, "style", ticket.style || row.style || "");
			frappe.model.set_value(cdt, cdn, "color_code", ticket.color_code || row.color_code || "");
		});
	}
});

frappe.ui.form.on("Work Order", {
	production_ticket(frm) {
		if (!frm.doc.production_ticket) {
			return;
		}

		frappe.db.get_value(
			"Production Ticket",
			frm.doc.production_ticket,
			["style", "color_code"]
		).then((response) => {
			const ticket = response.message || {};
			if (ticket.style) {
				frm.set_value("style", ticket.style);
			}
			if (ticket.color_code) {
				frm.set_value("color_code", ticket.color_code);
			}
		});
	}
});
